ps.arrival_at >= #{statDate}::date
AND ps.arrival_at < (#{statDate}::date + INTERVAL '1 day')

    AND ps.location_id = #{locationId}

mapper.select:
SELECT COALESCE(day_stats.session_count, 0) AS sessionCount, COALESCE(day_stats.visitor_count, 0) AS visitorCount, COALESCE(day_stats.known_visitor_count, 0) AS knownVisitorCount, COALESCE(day_stats.stranger_visitor_count, 0) AS strangerVisitorCount, COALESCE(open_stats.open_session_count, 0) AS openSessionCount, COALESCE(day_stats.closed_dwell_seconds, 0) AS closedDwellSeconds, COALESCE(day_stats.open_dwell_seconds, 0) AS openDwellSeconds FROM ( SELECT COUNT(*)::bigint AS session_count, COUNT(DISTINCT CASE WHEN ps.person_id IS NOT NULL THEN 'p:' || ps.person_id::text ELSE 't:' || ps.track_key END)::bigint AS visitor_count, COUNT(DISTINCT CASE WHEN ps.person_id IS NOT NULL AND p.person_type IN ('student', 'staff') THEN ps.person_id END)::bigint AS known_visitor_count, COUNT(DISTINCT CASE WHEN ps.person_id IS NULL THEN ps.track_key WHEN p.person_type = 'stranger' THEN 'p:' || ps.person_id::text END)::bigint AS stranger_visitor_count, COALESCE(SUM( CASE WHEN ps.status = 'closed' THEN ps.dwell_seconds ELSE 0 END ), 0)::bigint AS closed_dwell_seconds, COALESCE(SUM( CASE WHEN ps.status = 'open' THEN GREATEST(0, FLOOR(EXTRACT(EPOCH FROM (NOW() - ps.arrival_at))))::bigint ELSE 0 END ), 0)::bigint AS open_dwell_seconds FROM presence_sessions ps LEFT JOIN persons p ON p.id = ps.person_id
) day_stats CROSS JOIN ( SELECT COUNT(*)::bigint AS open_session_count FROM presence_sessions ps
) open_stats

SELECT l.id AS locationId, l.name AS locationName, l.device_serial AS deviceSerial, l.channel_no AS channelNo, COUNT(ps.id)::bigint AS sessionCount, COALESCE(SUM( CASE WHEN ps.id IS NULL THEN 0 WHEN ps.status = 'closed' THEN ps.dwell_seconds ELSE GREATEST(0, FLOOR(EXTRACT(EPOCH FROM (NOW() - ps.arrival_at))))::bigint END ), 0)::bigint AS dwellSeconds, COUNT(ps.id) FILTER (WHERE ps.status = 'open')::bigint AS openCount FROM locations l LEFT JOIN presence_sessions ps ON ps.location_id = l.id AND ps.arrival_at >= #{statDate}::date AND ps.arrival_at < (#{statDate}::date + INTERVAL '1 day') WHERE l.is_active = TRUE
AND l.id = #{locationId}
GROUP BY l.id, l.name, l.device_serial, l.channel_no ORDER BY sessionCount DESC, l.id

SELECT ps.id AS sessionId, ps.person_id AS personId, COALESCE(p.display_name, '未知访客') AS displayName, COALESCE(p.person_type::text, 'stranger') AS personKind, l.name AS locationName, ps.arrival_at AS arrivalAt, ps.departure_at AS departureAt, ps.status::text AS status, CASE WHEN ps.status = 'closed' THEN ps.dwell_seconds::bigint ELSE GREATEST(0, FLOOR(EXTRACT(EPOCH FROM (NOW() - ps.arrival_at))))::bigint END AS dwellSeconds, fp.image_url AS face_image_url FROM presence_sessions ps INNER JOIN locations l ON l.id = ps.location_id LEFT JOIN persons p ON p.id = ps.person_id LEFT JOIN LATERAL ( SELECT image_url FROM face_profiles WHERE person_id = ps.person_id ORDER BY is_primary DESC, created_at DESC LIMIT 1 ) fp ON ps.person_id IS NOT NULL
( (ps.arrival_at >= #{statDate}::date AND ps.arrival_at < (#{statDate}::date + INTERVAL '1 day')) OR ps.status = 'open' )
AND ps.location_id = #{locationId}
ORDER BY ps.arrival_at DESC LIMIT #{limit}

SELECT x.track_key AS trackKey, COALESCE(x.display_name, '未知访客') AS displayName, COALESCE(x.tags_text, '') AS tagsText, fp.image_url AS face_image_url, x.person_id AS mergedPersonId FROM ( SELECT DISTINCT ON (ps.track_key) ps.track_key, ps.person_id, p.display_name, COALESCE(array_to_string(p.tags, ','), '') AS tags_text, ps.arrival_at FROM presence_sessions ps LEFT JOIN persons p ON p.id = ps.person_id WHERE ps.track_key IS NOT NULL AND ps.track_key <> ''
AND ps.location_id = #{locationId}
AND (ps.person_id IS NULL OR p.person_type = 'stranger') ORDER BY ps.track_key, ps.arrival_at DESC ) x LEFT JOIN LATERAL ( SELECT image_url FROM face_profiles WHERE person_id = x.person_id ORDER BY is_primary DESC, created_at DESC LIMIT 1 ) fp ON x.person_id IS NOT NULL ORDER BY x.arrival_at DESC

mapper.update:
UPDATE presence_sessions
SET person_id = NULL, updated_at = NOW()
WHERE track_key = #{trackKey}

UPDATE presence_sessions
SET person_id = #{personId}, updated_at = NOW()
WHERE track_key = #{trackKey}
